class AutoID(type):
    def __init__(cls, name, bases, ns):
        super().__init__(name, bases, ns)
        cls._next = 0                    # per-class counter
    def __call__(cls, *a, **k):
        obj = super().__call__(*a, **k)  # normal construction
        obj.id = cls._next
        cls._next += 1
        return obj

class Order(metaclass=AutoID):
    pass

print(Order().id, Order().id)            # 0 1

