import sys

class Positive:
    """Data descriptor: enforces value > 0, stores per-instance."""
    def __set_name__(self, owner, name):
        self.slot = "_" + name
    def __get__(self, obj, owner=None):
        if obj is None:
            return self
        return getattr(obj, self.slot, None)
    def __set__(self, obj, value):
        if value <= 0:
            raise ValueError(value)
        setattr(obj, self.slot, value)

class Account:
    balance = Positive()

def main():
    data = sys.stdin.read().split("\n")
    n = int(data[0])
    acc = Account()
    out = []
    for i in range(1, n + 1):
        parts = data[i].split()
        if not parts:
            continue
        if parts[0] == "GET":
            v = acc.balance
            out.append("UNSET" if v is None else str(v))
        elif parts[0] == "SET":
            try:
                acc.balance = int(parts[1])
            except ValueError:
                out.append("REJECT")
    sys.stdout.write("\n".join(out) + "\n")

main()

