import sys

class AutoID(type):
    def __init__(cls, name, bases, ns):
        super().__init__(name, bases, ns)
        cls._next = 0
    def __call__(cls, *args, **kwargs):
        obj = super().__call__(*args, **kwargs)
        obj.id = cls._next
        cls._next += 1
        return obj

class Order(metaclass=AutoID):
    pass

class Trade(metaclass=AutoID):
    pass

def main():
    lines = sys.stdin.read().split("\n")
    n = int(lines[0])
    registry = {"Order": Order, "Trade": Trade}
    out = []
    for i in range(1, n + 1):
        name = lines[i].strip()
        if not name:
            continue
        obj = registry[name]()
        out.append(f"{name}#{obj.id}")
    sys.stdout.write("\n".join(out) + "\n")

main()

import sys

class Transaction:
    """Snapshot on enter; rollback + suppress on exception; commit on clean exit."""
    def __init__(self, target):
        self.target = target
    def __enter__(self):
        self._snapshot = list(self.target)
        return self.target
    def __exit__(self, exc_type, exc, tb):
        if exc_type is not None:
            self.target[:] = self._snapshot
            return True
        return False

def main():
    lines = sys.stdin.read().split("\n")
    n = int(lines[0])
    state = []
    for i in range(1, n + 1):
        nums = [int(x) for x in lines[i].split()]
        with Transaction(state) as s:
            for v in nums:
                if v == 0:
                    raise ValueError("poison")
                s.append(v)
    sys.stdout.write(" ".join(map(str, state)) + "\n")

main()
